const titles = $input.first().json.titles || [];
const links = $input.first().json.links || [];
const dates = $input.first().json.dates || [];
const sourceName = $('Split Sources').item.json.name;
const sourceUrl = $('Split Sources').item.json.url;

const articles = [];
const count = Math.min(titles.length, links.length);

for (let i = 0; i < count; i++) {
  let link = links[i];
  if (link && !link.startsWith('http')) {
    const base = new URL(sourceUrl);
    link = link.startsWith('/') ? base.origin + link : base.origin + '/' + link;
  }
  if (!link) continue;

  articles.push({
    json: {
      title: (titles[i] || '').trim(),
      source_url: link.trim(),
      published_date: (dates[i] || '').trim() || null,
      source_site: sourceName
    }
  });
}

return articles.length > 0 ? articles : [{ json: { _empty: true, source_site: sourceName } }];

const items = $input.all();
const newArticles = items.filter(item => item.json.id);
const allArticles = items.map(item => ({
  title: item.json.title || $('Normalize Articles').item.json.title,
  source_url: $('Normalize Articles').item.json.source_url
}));

return [{
  json: {
    new_count: newArticles.length,
    total_count: items.length,
    new_articles: newArticles,
    article_titles: allArticles.filter(a => a.title).map(a => a.title).join('\n- ')
  }
}];

